window.BIBLE["Galatians"] = {"1":{"chapter":"1","title":"Galatians 1","verses":{"1":{"text":"Paul, an apostle, (not of men, neither by man, but by Jesus Christ, and God the Father, who raised him from the dead;)","ref":"Galatians 1:1","synthesized":"Paul, an apostle, (not of men, neither by man, but by Jesus Christ, and God the Father, who raised him from the dead;)","sources":{"KJV":{"text":"Paul, an apostle, (not of men, neither by man, but by Jesus Christ, and God the Father, who raised him from the dead;)"}},"definableWords":["men","man","God","father"],"peopleInVerse":["Paul","Jesus"]},"2":{"text":"And all the brethren which are with me, unto the churches of Galatia:","ref":"Galatians 1:2","synthesized":"And all the brethren which are with me, unto the churches of Galatia:","sources":{"KJV":{"text":"And all the brethren which are with me, unto the churches of Galatia:"}},"definableWords":["brethren"],"peopleInVerse":[]},"3":{"text":"Grace be to you and peace from God the Father, and from our Lord Jesus Christ,","ref":"Galatians 1:3","synthesized":"Grace be to you and peace from God the Father, and from our Lord Jesus Christ,","sources":{"KJV":{"text":"Grace be to you and peace from God the Father, and from our Lord Jesus Christ,"}},"definableWords":["peace","God","father","Lord"],"peopleInVerse":["Jesus"]},"4":{"text":"Who gave himself for our sins, that he might deliver us from this present evil world, according to the will of God and our Father:","ref":"Galatians 1:4","synthesized":"Who gave himself for our sins, that he might deliver us from this present evil world, according to the will of God and our Father:","sources":{"KJV":{"text":"Who gave himself for our sins, that he might deliver us from this present evil world, according to the will of God and our Father:"}},"definableWords":["evil","God","father"],"peopleInVerse":[]},"5":{"text":"To whom be glory for ever and ever. Amen.","ref":"Galatians 1:5","synthesized":"To whom be glory for ever and ever. Amen.","sources":{"KJV":{"text":"To whom be glory for ever and ever. Amen."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"I marvel that ye are so soon removed from him that called you into the grace of Christ unto another gospel:","ref":"Galatians 1:6","synthesized":"I marvel that ye are so soon removed from him that called you into the grace of Christ unto another gospel:","sources":{"KJV":{"text":"I marvel that ye are so soon removed from him that called you into the grace of Christ unto another gospel:"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Which is not another; but there be some that trouble you, and would pervert the gospel of Christ.","ref":"Galatians 1:7","synthesized":"Which is not another; but there be some that trouble you, and would pervert the gospel of Christ.","sources":{"KJV":{"text":"Which is not another; but there be some that trouble you, and would pervert the gospel of Christ."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"But though we, or an angel from heaven, preach any other gospel unto you than that which we have preached unto you, let him be accursed.","ref":"Galatians 1:8","synthesized":"But though we, or an angel from heaven, preach any other gospel unto you than that which we have preached unto you, let him be accursed.","sources":{"KJV":{"text":"But though we, or an angel from heaven, preach any other gospel unto you than that which we have preached unto you, let him be accursed."}},"definableWords":["or","heaven"],"peopleInVerse":[]},"9":{"text":"As we said before, so say I now again, If any man preach any other gospel unto you than that ye have received, let him be accursed.","ref":"Galatians 1:9","synthesized":"As we said before, so say I now again, If any man preach any other gospel unto you than that ye have received, let him be accursed.","sources":{"KJV":{"text":"As we said before, so say I now again, If any man preach any other gospel unto you than that ye have received, let him be accursed."}},"definableWords":["man"],"peopleInVerse":[]},"10":{"text":"For do I now persuade men, or God? or do I seek to please men? for if I yet pleased men, I should not be the servant of Christ.","ref":"Galatians 1:10","synthesized":"For do I now persuade men, or God? or do I seek to please men? for if I yet pleased men, I should not be the servant of Christ.","sources":{"KJV":{"text":"For do I now persuade men, or God? or do I seek to please men? for if I yet pleased men, I should not be the servant of Christ."}},"definableWords":["men","or","God","servant"],"peopleInVerse":[]},"11":{"text":"But I certify you, brethren, that the gospel which was preached of me is not after man.","ref":"Galatians 1:11","synthesized":"But I certify you, brethren, that the gospel which was preached of me is not after man.","sources":{"KJV":{"text":"But I certify you, brethren, that the gospel which was preached of me is not after man."}},"definableWords":["brethren","man"],"peopleInVerse":[]},"12":{"text":"For I neither received it of man, neither was I taught it, but by the revelation of Jesus Christ.","ref":"Galatians 1:12","synthesized":"For I neither received it of man, neither was I taught it, but by the revelation of Jesus Christ.","sources":{"KJV":{"text":"For I neither received it of man, neither was I taught it, but by the revelation of Jesus Christ."}},"definableWords":["man"],"peopleInVerse":["Jesus"]},"13":{"text":"For ye have heard of my conversation in time past in the Jews’ religion, how that beyond measure I persecuted the church of God, and wasted it:","ref":"Galatians 1:13","synthesized":"For ye have heard of my conversation in time past in the Jews’ religion, how that beyond measure I persecuted the church of God, and wasted it:","sources":{"KJV":{"text":"For ye have heard of my conversation in time past in the Jews’ religion, how that beyond measure I persecuted the church of God, and wasted it:"}},"definableWords":["God"],"peopleInVerse":[]},"14":{"text":"And profited in the Jews’ religion above many my equals in mine own nation, being more exceedingly zealous of the traditions of my fathers.","ref":"Galatians 1:14","synthesized":"And profited in the Jews’ religion above many my equals in mine own nation, being more exceedingly zealous of the traditions of my fathers.","sources":{"KJV":{"text":"And profited in the Jews’ religion above many my equals in mine own nation, being more exceedingly zealous of the traditions of my fathers."}},"definableWords":["nation","fathers"],"peopleInVerse":[]},"15":{"text":"But when it pleased God, who separated me from my mother’s womb, and called me by his grace,","ref":"Galatians 1:15","synthesized":"But when it pleased God, who separated me from my mother’s womb, and called me by his grace,","sources":{"KJV":{"text":"But when it pleased God, who separated me from my mother’s womb, and called me by his grace,"}},"definableWords":["God","mother"],"peopleInVerse":[]},"16":{"text":"To reveal his Son in me, that I might preach him among the heathen; immediately I conferred not with flesh and blood:","ref":"Galatians 1:16","synthesized":"To reveal his Son in me, that I might preach him among the heathen; immediately I conferred not with flesh and blood:","sources":{"KJV":{"text":"To reveal his Son in me, that I might preach him among the heathen; immediately I conferred not with flesh and blood:"}},"definableWords":["son","flesh","blood"],"peopleInVerse":[]},"17":{"text":"Neither went I up to Jerusalem to them which were apostles before me; but I went into Arabia, and returned again unto Damascus.","ref":"Galatians 1:17","synthesized":"Neither went I up to Jerusalem to them which were apostles before me; but I went into Arabia, and returned again unto Damascus.","sources":{"KJV":{"text":"Neither went I up to Jerusalem to them which were apostles before me; but I went into Arabia, and returned again unto Damascus."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Then after three years I went up to Jerusalem to see Peter, and abode with him fifteen days.","ref":"Galatians 1:18","synthesized":"Then after three years I went up to Jerusalem to see Peter, and abode with him fifteen days.","sources":{"KJV":{"text":"Then after three years I went up to Jerusalem to see Peter, and abode with him fifteen days."}},"definableWords":["years","see","days"],"peopleInVerse":["Peter"]},"19":{"text":"But other of the apostles saw I none, save James the Lord’s brother.","ref":"Galatians 1:19","synthesized":"But other of the apostles saw I none, save James the Lord’s brother.","sources":{"KJV":{"text":"But other of the apostles saw I none, save James the Lord’s brother."}},"definableWords":["saw","Lord","brother"],"peopleInVerse":[]},"20":{"text":"Now the things which I write unto you, behold, before God, I lie not.","ref":"Galatians 1:20","synthesized":"Now the things which I write unto you, behold, before God, I lie not.","sources":{"KJV":{"text":"Now the things which I write unto you, behold, before God, I lie not."}},"definableWords":["God"],"peopleInVerse":[]},"21":{"text":"Afterwards I came into the regions of Syria and Cilicia;","ref":"Galatians 1:21","synthesized":"Afterwards I came into the regions of Syria and Cilicia;","sources":{"KJV":{"text":"Afterwards I came into the regions of Syria and Cilicia;"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"And was unknown by face unto the churches of Judaea which were in Christ:","ref":"Galatians 1:22","synthesized":"And was unknown by face unto the churches of Judaea which were in Christ:","sources":{"KJV":{"text":"And was unknown by face unto the churches of Judaea which were in Christ:"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"But they had heard only, That he which persecuted us in times past now preacheth the faith which once he destroyed.","ref":"Galatians 1:23","synthesized":"But they had heard only, That he which persecuted us in times past now preacheth the faith which once he destroyed.","sources":{"KJV":{"text":"But they had heard only, That he which persecuted us in times past now preacheth the faith which once he destroyed."}},"definableWords":["faith"],"peopleInVerse":[]},"24":{"text":"And they glorified God in me.","ref":"Galatians 1:24","synthesized":"And they glorified God in me.","sources":{"KJV":{"text":"And they glorified God in me."}},"definableWords":["God"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"Galatians 2","verses":{"1":{"text":"Then fourteen years after I went up again to Jerusalem with Barnabas, and took Titus with me also.","ref":"Galatians 2:1","synthesized":"Then fourteen years after I went up again to Jerusalem with Barnabas, and took Titus with me also.","sources":{"KJV":{"text":"Then fourteen years after I went up again to Jerusalem with Barnabas, and took Titus with me also."}},"definableWords":["years"],"peopleInVerse":[]},"2":{"text":"And I went up by revelation, and communicated unto them that gospel which I preach among the Gentiles, but privately to them which were of reputation, lest by any means I should run, or had run, in vain.","ref":"Galatians 2:2","synthesized":"And I went up by revelation, and communicated unto them that gospel which I preach among the Gentiles, but privately to them which were of reputation, lest by any means I should run, or had run, in vain.","sources":{"KJV":{"text":"And I went up by revelation, and communicated unto them that gospel which I preach among the Gentiles, but privately to them which were of reputation, lest by any means I should run, or had run, in vain."}},"definableWords":["or"],"peopleInVerse":[]},"3":{"text":"But neither Titus, who was with me, being a Greek, was compelled to be circumcised:","ref":"Galatians 2:3","synthesized":"But neither Titus, who was with me, being a Greek, was compelled to be circumcised:","sources":{"KJV":{"text":"But neither Titus, who was with me, being a Greek, was compelled to be circumcised:"}},"definableWords":["circumcised"],"peopleInVerse":[]},"4":{"text":"And that because of false brethren unawares brought in, who came in privily to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage:","ref":"Galatians 2:4","synthesized":"And that because of false brethren unawares brought in, who came in privily to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage:","sources":{"KJV":{"text":"And that because of false brethren unawares brought in, who came in privily to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage:"}},"definableWords":["brethren"],"peopleInVerse":["Jesus"]},"5":{"text":"To whom we gave place by subjection, no, not for an hour; that the truth of the gospel might continue with you.","ref":"Galatians 2:5","synthesized":"To whom we gave place by subjection, no, not for an hour; that the truth of the gospel might continue with you.","sources":{"KJV":{"text":"To whom we gave place by subjection, no, not for an hour; that the truth of the gospel might continue with you."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"But of these who seemed to be somewhat, (whatsoever they were, it maketh no matter to me: God accepteth no man’s person:) for they who seemed to be somewhat in conference added nothing to me:","ref":"Galatians 2:6","synthesized":"But of these who seemed to be somewhat, (whatsoever they were, it maketh no matter to me: God accepteth no man’s person:) for they who seemed to be somewhat in conference added nothing to me:","sources":{"KJV":{"text":"But of these who seemed to be somewhat, (whatsoever they were, it maketh no matter to me: God accepteth no man’s person:) for they who seemed to be somewhat in conference added nothing to me:"}},"definableWords":["God","man"],"peopleInVerse":[]},"7":{"text":"But contrariwise, when they saw that the gospel of the uncircumcision was committed unto me, as the gospel of the circumcision was unto Peter;","ref":"Galatians 2:7","synthesized":"But contrariwise, when they saw that the gospel of the uncircumcision was committed unto me, as the gospel of the circumcision was unto Peter;","sources":{"KJV":{"text":"But contrariwise, when they saw that the gospel of the uncircumcision was committed unto me, as the gospel of the circumcision was unto Peter;"}},"definableWords":["saw","circumcision"],"peopleInVerse":["Peter"]},"8":{"text":"(For he that wrought effectually in Peter to the apostleship of the circumcision, the same was mighty in me toward the Gentiles:)","ref":"Galatians 2:8","synthesized":"(For he that wrought effectually in Peter to the apostleship of the circumcision, the same was mighty in me toward the Gentiles:)","sources":{"KJV":{"text":"(For he that wrought effectually in Peter to the apostleship of the circumcision, the same was mighty in me toward the Gentiles:)"}},"definableWords":["circumcision","mighty"],"peopleInVerse":["Peter"]},"9":{"text":"And when James, Cephas, and John, who seemed to be pillars, perceived the grace that was given unto me, they gave to me and Barnabas the right hands of fellowship; that we should go unto the heathen, and they unto the circumcision.","ref":"Galatians 2:9","synthesized":"And when James, Cephas, and John, who seemed to be pillars, perceived the grace that was given unto me, they gave to me and Barnabas the right hands of fellowship; that we should go unto the heathen, and they unto the circumcision.","sources":{"KJV":{"text":"And when James, Cephas, and John, who seemed to be pillars, perceived the grace that was given unto me, they gave to me and Barnabas the right hands of fellowship; that we should go unto the heathen, and they unto the circumcision."}},"definableWords":["circumcision"],"peopleInVerse":[]},"10":{"text":"Only they would that we should remember the poor; the same which I also was forward to do.","ref":"Galatians 2:10","synthesized":"Only they would that we should remember the poor; the same which I also was forward to do.","sources":{"KJV":{"text":"Only they would that we should remember the poor; the same which I also was forward to do."}},"definableWords":["remember"],"peopleInVerse":[]},"11":{"text":"But when Peter was come to Antioch, I withstood him to the face, because he was to be blamed.","ref":"Galatians 2:11","synthesized":"But when Peter was come to Antioch, I withstood him to the face, because he was to be blamed.","sources":{"KJV":{"text":"But when Peter was come to Antioch, I withstood him to the face, because he was to be blamed."}},"definableWords":[],"peopleInVerse":["Peter"]},"12":{"text":"For before that certain came from James, he did eat with the Gentiles: but when they were come, he withdrew and separated himself, fearing them which were of the circumcision.","ref":"Galatians 2:12","synthesized":"For before that certain came from James, he did eat with the Gentiles: but when they were come, he withdrew and separated himself, fearing them which were of the circumcision.","sources":{"KJV":{"text":"For before that certain came from James, he did eat with the Gentiles: but when they were come, he withdrew and separated himself, fearing them which were of the circumcision."}},"definableWords":["circumcision"],"peopleInVerse":[]},"13":{"text":"And the other Jews dissembled likewise with him; insomuch that Barnabas also was carried away with their dissimulation.","ref":"Galatians 2:13","synthesized":"And the other Jews dissembled likewise with him; insomuch that Barnabas also was carried away with their dissimulation.","sources":{"KJV":{"text":"And the other Jews dissembled likewise with him; insomuch that Barnabas also was carried away with their dissimulation."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"But when I saw that they walked not uprightly according to the truth of the gospel, I said unto Peter before them all, If thou, being a Jew, livest after the manner of Gentiles, and not as do the Jews, why compellest thou the Gentiles to live as do the Jews?","ref":"Galatians 2:14","synthesized":"But when I saw that they walked not uprightly according to the truth of the gospel, I said unto Peter before them all, If thou, being a Jew, livest after the manner of Gentiles, and not as do the Jews, why compellest thou the Gentiles to live as do the Jews?","sources":{"KJV":{"text":"But when I saw that they walked not uprightly according to the truth of the gospel, I said unto Peter before them all, If thou, being a Jew, livest after the manner of Gentiles, and not as do the Jews, why compellest thou the Gentiles to live as do the Jews?"}},"definableWords":["saw","walked","live"],"peopleInVerse":["Peter"]},"15":{"text":"We who are Jews by nature, and not sinners of the Gentiles,","ref":"Galatians 2:15","synthesized":"We who are Jews by nature, and not sinners of the Gentiles,","sources":{"KJV":{"text":"We who are Jews by nature, and not sinners of the Gentiles,"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Knowing that a man is not justified by the works of the law, but by the faith of Jesus Christ, even we have believed in Jesus Christ, that we might be justified by the faith of Christ, and not by the works of the law: for by the works of the law shall no flesh be justified.","ref":"Galatians 2:16","synthesized":"Knowing that a man is not justified by the works of the law, but by the faith of Jesus Christ, even we have believed in Jesus Christ, that we might be justified by the faith of Christ, and not by the works of the law: for by the works of the law shall no flesh be justified.","sources":{"KJV":{"text":"Knowing that a man is not justified by the works of the law, but by the faith of Jesus Christ, even we have believed in Jesus Christ, that we might be justified by the faith of Christ, and not by the works of the law: for by the works of the law shall no flesh be justified."}},"definableWords":["man","works","faith","believed","flesh"],"peopleInVerse":["Jesus"]},"17":{"text":"But if, while we seek to be justified by Christ, we ourselves also are found sinners, is therefore Christ the minister of sin? God forbid.","ref":"Galatians 2:17","synthesized":"But if, while we seek to be justified by Christ, we ourselves also are found sinners, is therefore Christ the minister of sin? God forbid.","sources":{"KJV":{"text":"But if, while we seek to be justified by Christ, we ourselves also are found sinners, is therefore Christ the minister of sin? God forbid."}},"definableWords":["sin","God"],"peopleInVerse":[]},"18":{"text":"For if I build again the things which I destroyed, I make myself a transgressor.","ref":"Galatians 2:18","synthesized":"For if I build again the things which I destroyed, I make myself a transgressor.","sources":{"KJV":{"text":"For if I build again the things which I destroyed, I make myself a transgressor."}},"definableWords":["make"],"peopleInVerse":[]},"19":{"text":"For I through the law am dead to the law, that I might live unto God.","ref":"Galatians 2:19","synthesized":"For I through the law am dead to the law, that I might live unto God.","sources":{"KJV":{"text":"For I through the law am dead to the law, that I might live unto God."}},"definableWords":["live","God"],"peopleInVerse":[]},"20":{"text":"I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me.","ref":"Galatians 2:20","synthesized":"I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me.","sources":{"KJV":{"text":"I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me."}},"definableWords":["live","life","flesh","faith","son","God"],"peopleInVerse":[]},"21":{"text":"I do not frustrate the grace of God: for if righteousness come by the law, then Christ is dead in vain.","ref":"Galatians 2:21","synthesized":"I do not frustrate the grace of God: for if righteousness come by the law, then Christ is dead in vain.","sources":{"KJV":{"text":"I do not frustrate the grace of God: for if righteousness come by the law, then Christ is dead in vain."}},"definableWords":["God","righteousness"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"Galatians 3","verses":{"1":{"text":"O foolish Galatians, who hath bewitched you, that ye should not obey the truth, before whose eyes Jesus Christ hath been evidently set forth, crucified among you?","ref":"Galatians 3:1","synthesized":"O foolish Galatians, who hath bewitched you, that ye should not obey the truth, before whose eyes Jesus Christ hath been evidently set forth, crucified among you?","sources":{"KJV":{"text":"O foolish Galatians, who hath bewitched you, that ye should not obey the truth, before whose eyes Jesus Christ hath been evidently set forth, crucified among you?"}},"definableWords":[],"peopleInVerse":["Jesus"]},"2":{"text":"This only would I learn of you, Received ye the Spirit by the works of the law, or by the hearing of faith?","ref":"Galatians 3:2","synthesized":"This only would I learn of you, Received ye the Spirit by the works of the law, or by the hearing of faith?","sources":{"KJV":{"text":"This only would I learn of you, Received ye the Spirit by the works of the law, or by the hearing of faith?"}},"definableWords":["Spirit","works","or","faith"],"peopleInVerse":[]},"3":{"text":"Are ye so foolish? having begun in the Spirit, are ye now made perfect by the flesh?","ref":"Galatians 3:3","synthesized":"Are ye so foolish? having begun in the Spirit, are ye now made perfect by the flesh?","sources":{"KJV":{"text":"Are ye so foolish? having begun in the Spirit, are ye now made perfect by the flesh?"}},"definableWords":["Spirit","made","flesh"],"peopleInVerse":[]},"4":{"text":"Have ye suffered so many things in vain? if it be yet in vain.","ref":"Galatians 3:4","synthesized":"Have ye suffered so many things in vain? if it be yet in vain.","sources":{"KJV":{"text":"Have ye suffered so many things in vain? if it be yet in vain."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"He therefore that ministereth to you the Spirit, and worketh miracles among you, doeth he it by the works of the law, or by the hearing of faith?","ref":"Galatians 3:5","synthesized":"He therefore that ministereth to you the Spirit, and worketh miracles among you, doeth he it by the works of the law, or by the hearing of faith?","sources":{"KJV":{"text":"He therefore that ministereth to you the Spirit, and worketh miracles among you, doeth he it by the works of the law, or by the hearing of faith?"}},"definableWords":["Spirit","works","or","faith"],"peopleInVerse":[]},"6":{"text":"Even as Abraham believed God, and it was accounted to him for righteousness.","ref":"Galatians 3:6","synthesized":"Even as Abraham believed God, and it was accounted to him for righteousness.","sources":{"KJV":{"text":"Even as Abraham believed God, and it was accounted to him for righteousness."}},"definableWords":["Abraham","believed","God","righteousness"],"peopleInVerse":["Abraham"]},"7":{"text":"Know ye therefore that they which are of faith, the same are the children of Abraham.","ref":"Galatians 3:7","synthesized":"Know ye therefore that they which are of faith, the same are the children of Abraham.","sources":{"KJV":{"text":"Know ye therefore that they which are of faith, the same are the children of Abraham."}},"definableWords":["faith","Abraham"],"peopleInVerse":["Abraham"]},"8":{"text":"And the scripture, foreseeing that God would justify the heathen through faith, preached before the gospel unto Abraham, saying, In thee shall all nations be blessed.","ref":"Galatians 3:8","synthesized":"And the scripture, foreseeing that God would justify the heathen through faith, preached before the gospel unto Abraham, saying, In thee shall all nations be blessed.","sources":{"KJV":{"text":"And the scripture, foreseeing that God would justify the heathen through faith, preached before the gospel unto Abraham, saying, In thee shall all nations be blessed."}},"definableWords":["God","faith","Abraham","nations","blessed"],"peopleInVerse":["Abraham"]},"9":{"text":"So then they which be of faith are blessed with faithful Abraham.","ref":"Galatians 3:9","synthesized":"So then they which be of faith are blessed with faithful Abraham.","sources":{"KJV":{"text":"So then they which be of faith are blessed with faithful Abraham."}},"definableWords":["faith","blessed","Abraham"],"peopleInVerse":["Abraham"]},"10":{"text":"For as many as are of the works of the law are under the curse: for it is written, Cursed is every one that continueth not in all things which are written in the book of the law to do them.","ref":"Galatians 3:10","synthesized":"For as many as are of the works of the law are under the curse: for it is written, Cursed is every one that continueth not in all things which are written in the book of the law to do them.","sources":{"KJV":{"text":"For as many as are of the works of the law are under the curse: for it is written, Cursed is every one that continueth not in all things which are written in the book of the law to do them."}},"definableWords":["works","curse","cursed","one"],"peopleInVerse":[]},"11":{"text":"But that no man is justified by the law in the sight of God, it is evident: for, The just shall live by faith.","ref":"Galatians 3:11","synthesized":"But that no man is justified by the law in the sight of God, it is evident: for, The just shall live by faith.","sources":{"KJV":{"text":"But that no man is justified by the law in the sight of God, it is evident: for, The just shall live by faith."}},"definableWords":["man","God","live","faith"],"peopleInVerse":[]},"12":{"text":"And the law is not of faith: but, The man that doeth them shall live in them.","ref":"Galatians 3:12","synthesized":"And the law is not of faith: but, The man that doeth them shall live in them.","sources":{"KJV":{"text":"And the law is not of faith: but, The man that doeth them shall live in them."}},"definableWords":["faith","man","live"],"peopleInVerse":[]},"13":{"text":"Christ hath redeemed us from the curse of the law, being made a curse for us: for it is written, Cursed is every one that hangeth on a tree:","ref":"Galatians 3:13","synthesized":"Christ hath redeemed us from the curse of the law, being made a curse for us: for it is written, Cursed is every one that hangeth on a tree:","sources":{"KJV":{"text":"Christ hath redeemed us from the curse of the law, being made a curse for us: for it is written, Cursed is every one that hangeth on a tree:"}},"definableWords":["curse","made","cursed","one","tree"],"peopleInVerse":[]},"14":{"text":"That the blessing of Abraham might come on the Gentiles through Jesus Christ; that we might receive the promise of the Spirit through faith.","ref":"Galatians 3:14","synthesized":"That the blessing of Abraham might come on the Gentiles through Jesus Christ; that we might receive the promise of the Spirit through faith.","sources":{"KJV":{"text":"That the blessing of Abraham might come on the Gentiles through Jesus Christ; that we might receive the promise of the Spirit through faith."}},"definableWords":["blessing","Abraham","promise","Spirit","faith"],"peopleInVerse":["Abraham","Jesus"]},"15":{"text":"Brethren, I speak after the manner of men; Though it be but a man’s covenant, yet if it be confirmed, no man disannulleth, or addeth thereto.","ref":"Galatians 3:15","synthesized":"Brethren, I speak after the manner of men; Though it be but a man’s covenant, yet if it be confirmed, no man disannulleth, or addeth thereto.","sources":{"KJV":{"text":"Brethren, I speak after the manner of men; Though it be but a man’s covenant, yet if it be confirmed, no man disannulleth, or addeth thereto."}},"definableWords":["brethren","men","man","covenant","or"],"peopleInVerse":[]},"16":{"text":"Now to Abraham and his seed were the promises made. He saith not, And to seeds, as of many; but as of one, And to thy seed, which is Christ.","ref":"Galatians 3:16","synthesized":"Now to Abraham and his seed were the promises made. He saith not, And to seeds, as of many; but as of one, And to thy seed, which is Christ.","sources":{"KJV":{"text":"Now to Abraham and his seed were the promises made. He saith not, And to seeds, as of many; but as of one, And to thy seed, which is Christ."}},"definableWords":["Abraham","seed","made","one"],"peopleInVerse":["Abraham"]},"17":{"text":"And this I say, that the covenant, that was confirmed before of God in Christ, the law, which was four hundred and thirty years after, cannot disannul, that it should make the promise of none effect.","ref":"Galatians 3:17","synthesized":"And this I say, that the covenant, that was confirmed before of God in Christ, the law, which was four hundred and thirty years after, cannot disannul, that it should make the promise of none effect.","sources":{"KJV":{"text":"And this I say, that the covenant, that was confirmed before of God in Christ, the law, which was four hundred and thirty years after, cannot disannul, that it should make the promise of none effect."}},"definableWords":["covenant","God","years","make","promise"],"peopleInVerse":[]},"18":{"text":"For if the inheritance be of the law, it is no more of promise: but God gave it to Abraham by promise.","ref":"Galatians 3:18","synthesized":"For if the inheritance be of the law, it is no more of promise: but God gave it to Abraham by promise.","sources":{"KJV":{"text":"For if the inheritance be of the law, it is no more of promise: but God gave it to Abraham by promise."}},"definableWords":["promise","God","Abraham"],"peopleInVerse":["Abraham"]},"19":{"text":"Wherefore then serveth the law? It was added because of transgressions, till the seed should come to whom the promise was made; and it was ordained by angels in the hand of a mediator.","ref":"Galatians 3:19","synthesized":"Wherefore then serveth the law? It was added because of transgressions, till the seed should come to whom the promise was made; and it was ordained by angels in the hand of a mediator.","sources":{"KJV":{"text":"Wherefore then serveth the law? It was added because of transgressions, till the seed should come to whom the promise was made; and it was ordained by angels in the hand of a mediator."}},"definableWords":["till","seed","promise","made"],"peopleInVerse":[]},"20":{"text":"Now a mediator is not a mediator of one, but God is one.","ref":"Galatians 3:20","synthesized":"Now a mediator is not a mediator of one, but God is one.","sources":{"KJV":{"text":"Now a mediator is not a mediator of one, but God is one."}},"definableWords":["one","God"],"peopleInVerse":[]},"21":{"text":"Is the law then against the promises of God? God forbid: for if there had been a law given which could have given life, verily righteousness should have been by the law.","ref":"Galatians 3:21","synthesized":"Is the law then against the promises of God? God forbid: for if there had been a law given which could have given life, verily righteousness should have been by the law.","sources":{"KJV":{"text":"Is the law then against the promises of God? God forbid: for if there had been a law given which could have given life, verily righteousness should have been by the law."}},"definableWords":["God","life","righteousness"],"peopleInVerse":[]},"22":{"text":"But the scripture hath concluded all under sin, that the promise by faith of Jesus Christ might be given to them that believe.","ref":"Galatians 3:22","synthesized":"But the scripture hath concluded all under sin, that the promise by faith of Jesus Christ might be given to them that believe.","sources":{"KJV":{"text":"But the scripture hath concluded all under sin, that the promise by faith of Jesus Christ might be given to them that believe."}},"definableWords":["sin","promise","faith"],"peopleInVerse":["Jesus"]},"23":{"text":"But before faith came, we were kept under the law, shut up unto the faith which should afterwards be revealed.","ref":"Galatians 3:23","synthesized":"But before faith came, we were kept under the law, shut up unto the faith which should afterwards be revealed.","sources":{"KJV":{"text":"But before faith came, we were kept under the law, shut up unto the faith which should afterwards be revealed."}},"definableWords":["faith"],"peopleInVerse":[]},"24":{"text":"Wherefore the law was our schoolmaster to bring us unto Christ, that we might be justified by faith.","ref":"Galatians 3:24","synthesized":"Wherefore the law was our schoolmaster to bring us unto Christ, that we might be justified by faith.","sources":{"KJV":{"text":"Wherefore the law was our schoolmaster to bring us unto Christ, that we might be justified by faith."}},"definableWords":["faith"],"peopleInVerse":[]},"25":{"text":"But after that faith is come, we are no longer under a schoolmaster.","ref":"Galatians 3:25","synthesized":"But after that faith is come, we are no longer under a schoolmaster.","sources":{"KJV":{"text":"But after that faith is come, we are no longer under a schoolmaster."}},"definableWords":["faith"],"peopleInVerse":[]},"26":{"text":"For ye are all the children of God by faith in Christ Jesus.","ref":"Galatians 3:26","synthesized":"For ye are all the children of God by faith in Christ Jesus.","sources":{"KJV":{"text":"For ye are all the children of God by faith in Christ Jesus."}},"definableWords":["God","faith"],"peopleInVerse":["Jesus"]},"27":{"text":"For as many of you as have been baptized into Christ have put on Christ.","ref":"Galatians 3:27","synthesized":"For as many of you as have been baptized into Christ have put on Christ.","sources":{"KJV":{"text":"For as many of you as have been baptized into Christ have put on Christ."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"There is neither Jew nor Greek, there is neither bond nor free, there is neither male nor female: for ye are all one in Christ Jesus.","ref":"Galatians 3:28","synthesized":"There is neither Jew nor Greek, there is neither bond nor free, there is neither male nor female: for ye are all one in Christ Jesus.","sources":{"KJV":{"text":"There is neither Jew nor Greek, there is neither bond nor free, there is neither male nor female: for ye are all one in Christ Jesus."}},"definableWords":["male","female","one"],"peopleInVerse":["Jesus"]},"29":{"text":"And if ye be Christ’s, then are ye Abraham’s seed, and heirs according to the promise.","ref":"Galatians 3:29","synthesized":"And if ye be Christ’s, then are ye Abraham’s seed, and heirs according to the promise.","sources":{"KJV":{"text":"And if ye be Christ’s, then are ye Abraham’s seed, and heirs according to the promise."}},"definableWords":["Abraham","seed","promise"],"peopleInVerse":["Abraham"]}}},"4":{"chapter":"4","title":"Galatians 4","verses":{"1":{"text":"Now I say, That the heir, as long as he is a child, differeth nothing from a servant, though he be lord of all;","ref":"Galatians 4:1","synthesized":"Now I say, That the heir, as long as he is a child, differeth nothing from a servant, though he be lord of all;","sources":{"KJV":{"text":"Now I say, That the heir, as long as he is a child, differeth nothing from a servant, though he be lord of all;"}},"definableWords":["servant","Lord"],"peopleInVerse":[]},"2":{"text":"But is under tutors and governors until the time appointed of the father.","ref":"Galatians 4:2","synthesized":"But is under tutors and governors until the time appointed of the father.","sources":{"KJV":{"text":"But is under tutors and governors until the time appointed of the father."}},"definableWords":["father"],"peopleInVerse":[]},"3":{"text":"Even so we, when we were children, were in bondage under the elements of the world:","ref":"Galatians 4:3","synthesized":"Even so we, when we were children, were in bondage under the elements of the world:","sources":{"KJV":{"text":"Even so we, when we were children, were in bondage under the elements of the world:"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"But when the fulness of the time was come, God sent forth his Son, made of a woman, made under the law,","ref":"Galatians 4:4","synthesized":"But when the fulness of the time was come, God sent forth his Son, made of a woman, made under the law,","sources":{"KJV":{"text":"But when the fulness of the time was come, God sent forth his Son, made of a woman, made under the law,"}},"definableWords":["God","son","made","woman"],"peopleInVerse":[]},"5":{"text":"To redeem them that were under the law, that we might receive the adoption of sons.","ref":"Galatians 4:5","synthesized":"To redeem them that were under the law, that we might receive the adoption of sons.","sources":{"KJV":{"text":"To redeem them that were under the law, that we might receive the adoption of sons."}},"definableWords":["sons"],"peopleInVerse":[]},"6":{"text":"And because ye are sons, God hath sent forth the Spirit of his Son into your hearts, crying, Abba, Father.","ref":"Galatians 4:6","synthesized":"And because ye are sons, God hath sent forth the Spirit of his Son into your hearts, crying, Abba, Father.","sources":{"KJV":{"text":"And because ye are sons, God hath sent forth the Spirit of his Son into your hearts, crying, Abba, Father."}},"definableWords":["sons","God","Spirit","son","father"],"peopleInVerse":[]},"7":{"text":"Wherefore thou art no more a servant, but a son; and if a son, then an heir of God through Christ.","ref":"Galatians 4:7","synthesized":"Wherefore thou art no more a servant, but a son; and if a son, then an heir of God through Christ.","sources":{"KJV":{"text":"Wherefore thou art no more a servant, but a son; and if a son, then an heir of God through Christ."}},"definableWords":["servant","son","God"],"peopleInVerse":[]},"8":{"text":"Howbeit then, when ye knew not God, ye did service unto them which by nature are no gods.","ref":"Galatians 4:8","synthesized":"Howbeit then, when ye knew not God, ye did service unto them which by nature are no gods.","sources":{"KJV":{"text":"Howbeit then, when ye knew not God, ye did service unto them which by nature are no gods."}},"definableWords":["God"],"peopleInVerse":[]},"9":{"text":"But now, after that ye have known God, or rather are known of God, how turn ye again to the weak and beggarly elements, whereunto ye desire again to be in bondage?","ref":"Galatians 4:9","synthesized":"But now, after that ye have known God, or rather are known of God, how turn ye again to the weak and beggarly elements, whereunto ye desire again to be in bondage?","sources":{"KJV":{"text":"But now, after that ye have known God, or rather are known of God, how turn ye again to the weak and beggarly elements, whereunto ye desire again to be in bondage?"}},"definableWords":["God","or"],"peopleInVerse":[]},"10":{"text":"Ye observe days, and months, and times, and years.","ref":"Galatians 4:10","synthesized":"Ye observe days, and months, and times, and years.","sources":{"KJV":{"text":"Ye observe days, and months, and times, and years."}},"definableWords":["days","years"],"peopleInVerse":[]},"11":{"text":"I am afraid of you, lest I have bestowed upon you labour in vain.","ref":"Galatians 4:11","synthesized":"I am afraid of you, lest I have bestowed upon you labour in vain.","sources":{"KJV":{"text":"I am afraid of you, lest I have bestowed upon you labour in vain."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Brethren, I beseech you, be as I am; for I am as ye are: ye have not injured me at all.","ref":"Galatians 4:12","synthesized":"Brethren, I beseech you, be as I am; for I am as ye are: ye have not injured me at all.","sources":{"KJV":{"text":"Brethren, I beseech you, be as I am; for I am as ye are: ye have not injured me at all."}},"definableWords":["brethren"],"peopleInVerse":[]},"13":{"text":"Ye know how through infirmity of the flesh I preached the gospel unto you at the first.","ref":"Galatians 4:13","synthesized":"Ye know how through infirmity of the flesh I preached the gospel unto you at the first.","sources":{"KJV":{"text":"Ye know how through infirmity of the flesh I preached the gospel unto you at the first."}},"definableWords":["flesh"],"peopleInVerse":[]},"14":{"text":"And my temptation which was in my flesh ye despised not, nor rejected; but received me as an angel of God, even as Christ Jesus.","ref":"Galatians 4:14","synthesized":"And my temptation which was in my flesh ye despised not, nor rejected; but received me as an angel of God, even as Christ Jesus.","sources":{"KJV":{"text":"And my temptation which was in my flesh ye despised not, nor rejected; but received me as an angel of God, even as Christ Jesus."}},"definableWords":["flesh","God"],"peopleInVerse":["Jesus"]},"15":{"text":"Where is then the blessedness ye spake of? for I bear you record, that, if it had been possible, ye would have plucked out your own eyes, and have given them to me.","ref":"Galatians 4:15","synthesized":"Where is then the blessedness ye spake of? for I bear you record, that, if it had been possible, ye would have plucked out your own eyes, and have given them to me.","sources":{"KJV":{"text":"Where is then the blessedness ye spake of? for I bear you record, that, if it had been possible, ye would have plucked out your own eyes, and have given them to me."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Am I therefore become your enemy, because I tell you the truth?","ref":"Galatians 4:16","synthesized":"Am I therefore become your enemy, because I tell you the truth?","sources":{"KJV":{"text":"Am I therefore become your enemy, because I tell you the truth?"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"They zealously affect you, but not well; yea, they would exclude you, that ye might affect them.","ref":"Galatians 4:17","synthesized":"They zealously affect you, but not well; yea, they would exclude you, that ye might affect them.","sources":{"KJV":{"text":"They zealously affect you, but not well; yea, they would exclude you, that ye might affect them."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"But it is good to be zealously affected always in a good thing, and not only when I am present with you.","ref":"Galatians 4:18","synthesized":"But it is good to be zealously affected always in a good thing, and not only when I am present with you.","sources":{"KJV":{"text":"But it is good to be zealously affected always in a good thing, and not only when I am present with you."}},"definableWords":["good"],"peopleInVerse":[]},"19":{"text":"My little children, of whom I travail in birth again until Christ be formed in you,","ref":"Galatians 4:19","synthesized":"My little children, of whom I travail in birth again until Christ be formed in you,","sources":{"KJV":{"text":"My little children, of whom I travail in birth again until Christ be formed in you,"}},"definableWords":["formed"],"peopleInVerse":[]},"20":{"text":"I desire to be present with you now, and to change my voice; for I stand in doubt of you.","ref":"Galatians 4:20","synthesized":"I desire to be present with you now, and to change my voice; for I stand in doubt of you.","sources":{"KJV":{"text":"I desire to be present with you now, and to change my voice; for I stand in doubt of you."}},"definableWords":["voice"],"peopleInVerse":[]},"21":{"text":"Tell me, ye that desire to be under the law, do ye not hear the law?","ref":"Galatians 4:21","synthesized":"Tell me, ye that desire to be under the law, do ye not hear the law?","sources":{"KJV":{"text":"Tell me, ye that desire to be under the law, do ye not hear the law?"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"For it is written, that Abraham had two sons, the one by a bondmaid, the other by a freewoman.","ref":"Galatians 4:22","synthesized":"For it is written, that Abraham had two sons, the one by a bondmaid, the other by a freewoman.","sources":{"KJV":{"text":"For it is written, that Abraham had two sons, the one by a bondmaid, the other by a freewoman."}},"definableWords":["Abraham","sons","one"],"peopleInVerse":["Abraham"]},"23":{"text":"But he who was of the bondwoman was born after the flesh; but he of the freewoman was by promise.","ref":"Galatians 4:23","synthesized":"But he who was of the bondwoman was born after the flesh; but he of the freewoman was by promise.","sources":{"KJV":{"text":"But he who was of the bondwoman was born after the flesh; but he of the freewoman was by promise."}},"definableWords":["flesh","promise"],"peopleInVerse":[]},"24":{"text":"Which things are an allegory: for these are the two covenants; the one from the mount Sinai, which gendereth to bondage, which is Agar.","ref":"Galatians 4:24","synthesized":"Which things are an allegory: for these are the two covenants; the one from the mount Sinai, which gendereth to bondage, which is Agar.","sources":{"KJV":{"text":"Which things are an allegory: for these are the two covenants; the one from the mount Sinai, which gendereth to bondage, which is Agar."}},"definableWords":["one"],"peopleInVerse":[]},"25":{"text":"For this Agar is mount Sinai in Arabia, and answereth to Jerusalem which now is, and is in bondage with her children.","ref":"Galatians 4:25","synthesized":"For this Agar is mount Sinai in Arabia, and answereth to Jerusalem which now is, and is in bondage with her children.","sources":{"KJV":{"text":"For this Agar is mount Sinai in Arabia, and answereth to Jerusalem which now is, and is in bondage with her children."}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"But Jerusalem which is above is free, which is the mother of us all.","ref":"Galatians 4:26","synthesized":"But Jerusalem which is above is free, which is the mother of us all.","sources":{"KJV":{"text":"But Jerusalem which is above is free, which is the mother of us all."}},"definableWords":["mother"],"peopleInVerse":[]},"27":{"text":"For it is written, Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not: for the desolate hath many more children than she which hath an husband.","ref":"Galatians 4:27","synthesized":"For it is written, Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not: for the desolate hath many more children than she which hath an husband.","sources":{"KJV":{"text":"For it is written, Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not: for the desolate hath many more children than she which hath an husband."}},"definableWords":["husband"],"peopleInVerse":[]},"28":{"text":"Now we, brethren, as Isaac was, are the children of promise.","ref":"Galatians 4:28","synthesized":"Now we, brethren, as Isaac was, are the children of promise.","sources":{"KJV":{"text":"Now we, brethren, as Isaac was, are the children of promise."}},"definableWords":["brethren","Isaac","promise"],"peopleInVerse":[]},"29":{"text":"But as then he that was born after the flesh persecuted him that was born after the Spirit, even so it is now.","ref":"Galatians 4:29","synthesized":"But as then he that was born after the flesh persecuted him that was born after the Spirit, even so it is now.","sources":{"KJV":{"text":"But as then he that was born after the flesh persecuted him that was born after the Spirit, even so it is now."}},"definableWords":["flesh","Spirit"],"peopleInVerse":[]},"30":{"text":"Nevertheless what saith the scripture? Cast out the bondwoman and her son: for the son of the bondwoman shall not be heir with the son of the freewoman.","ref":"Galatians 4:30","synthesized":"Nevertheless what saith the scripture? Cast out the bondwoman and her son: for the son of the bondwoman shall not be heir with the son of the freewoman.","sources":{"KJV":{"text":"Nevertheless what saith the scripture? Cast out the bondwoman and her son: for the son of the bondwoman shall not be heir with the son of the freewoman."}},"definableWords":["son"],"peopleInVerse":[]},"31":{"text":"So then, brethren, we are not children of the bondwoman, but of the free.","ref":"Galatians 4:31","synthesized":"So then, brethren, we are not children of the bondwoman, but of the free.","sources":{"KJV":{"text":"So then, brethren, we are not children of the bondwoman, but of the free."}},"definableWords":["brethren"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"Galatians 5","verses":{"1":{"text":"Stand fast therefore in the liberty wherewith Christ hath made us free, and be not entangled again with the yoke of bondage.","ref":"Galatians 5:1","synthesized":"Stand fast therefore in the liberty wherewith Christ hath made us free, and be not entangled again with the yoke of bondage.","sources":{"KJV":{"text":"Stand fast therefore in the liberty wherewith Christ hath made us free, and be not entangled again with the yoke of bondage."}},"definableWords":["made"],"peopleInVerse":[]},"2":{"text":"Behold, I Paul say unto you, that if ye be circumcised, Christ shall profit you nothing.","ref":"Galatians 5:2","synthesized":"Behold, I Paul say unto you, that if ye be circumcised, Christ shall profit you nothing.","sources":{"KJV":{"text":"Behold, I Paul say unto you, that if ye be circumcised, Christ shall profit you nothing."}},"definableWords":["circumcised"],"peopleInVerse":["Paul"]},"3":{"text":"For I testify again to every man that is circumcised, that he is a debtor to do the whole law.","ref":"Galatians 5:3","synthesized":"For I testify again to every man that is circumcised, that he is a debtor to do the whole law.","sources":{"KJV":{"text":"For I testify again to every man that is circumcised, that he is a debtor to do the whole law."}},"definableWords":["man","circumcised"],"peopleInVerse":[]},"4":{"text":"Christ is become of no effect unto you, whosoever of you are justified by the law; ye are fallen from grace.","ref":"Galatians 5:4","synthesized":"Christ is become of no effect unto you, whosoever of you are justified by the law; ye are fallen from grace.","sources":{"KJV":{"text":"Christ is become of no effect unto you, whosoever of you are justified by the law; ye are fallen from grace."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"For we through the Spirit wait for the hope of righteousness by faith.","ref":"Galatians 5:5","synthesized":"For we through the Spirit wait for the hope of righteousness by faith.","sources":{"KJV":{"text":"For we through the Spirit wait for the hope of righteousness by faith."}},"definableWords":["Spirit","righteousness","faith"],"peopleInVerse":[]},"6":{"text":"For in Jesus Christ neither circumcision availeth any thing, nor uncircumcision; but faith which worketh by love.","ref":"Galatians 5:6","synthesized":"For in Jesus Christ neither circumcision availeth any thing, nor uncircumcision; but faith which worketh by love.","sources":{"KJV":{"text":"For in Jesus Christ neither circumcision availeth any thing, nor uncircumcision; but faith which worketh by love."}},"definableWords":["circumcision","faith","love"],"peopleInVerse":["Jesus"]},"7":{"text":"Ye did run well; who did hinder you that ye should not obey the truth?","ref":"Galatians 5:7","synthesized":"Ye did run well; who did hinder you that ye should not obey the truth?","sources":{"KJV":{"text":"Ye did run well; who did hinder you that ye should not obey the truth?"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"This persuasion cometh not of him that calleth you.","ref":"Galatians 5:8","synthesized":"This persuasion cometh not of him that calleth you.","sources":{"KJV":{"text":"This persuasion cometh not of him that calleth you."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"A little leaven leaveneth the whole lump.","ref":"Galatians 5:9","synthesized":"A little leaven leaveneth the whole lump.","sources":{"KJV":{"text":"A little leaven leaveneth the whole lump."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"I have confidence in you through the Lord, that ye will be none otherwise minded: but he that troubleth you shall bear his judgment, whosoever he be.","ref":"Galatians 5:10","synthesized":"I have confidence in you through the Lord, that ye will be none otherwise minded: but he that troubleth you shall bear his judgment, whosoever he be.","sources":{"KJV":{"text":"I have confidence in you through the Lord, that ye will be none otherwise minded: but he that troubleth you shall bear his judgment, whosoever he be."}},"definableWords":["Lord","judgment"],"peopleInVerse":[]},"11":{"text":"And I, brethren, if I yet preach circumcision, why do I yet suffer persecution? then is the offence of the cross ceased.","ref":"Galatians 5:11","synthesized":"And I, brethren, if I yet preach circumcision, why do I yet suffer persecution? then is the offence of the cross ceased.","sources":{"KJV":{"text":"And I, brethren, if I yet preach circumcision, why do I yet suffer persecution? then is the offence of the cross ceased."}},"definableWords":["brethren","circumcision"],"peopleInVerse":[]},"12":{"text":"I would they were even cut off which trouble you.","ref":"Galatians 5:12","synthesized":"I would they were even cut off which trouble you.","sources":{"KJV":{"text":"I would they were even cut off which trouble you."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"For, brethren, ye have been called unto liberty; only use not liberty for an occasion to the flesh, but by love serve one another.","ref":"Galatians 5:13","synthesized":"For, brethren, ye have been called unto liberty; only use not liberty for an occasion to the flesh, but by love serve one another.","sources":{"KJV":{"text":"For, brethren, ye have been called unto liberty; only use not liberty for an occasion to the flesh, but by love serve one another."}},"definableWords":["brethren","flesh","love","one"],"peopleInVerse":[]},"14":{"text":"For all the law is fulfilled in one word, even in this; Thou shalt love thy neighbour as thyself.","ref":"Galatians 5:14","synthesized":"For all the law is fulfilled in one word, even in this; Thou shalt love thy neighbour as thyself.","sources":{"KJV":{"text":"For all the law is fulfilled in one word, even in this; Thou shalt love thy neighbour as thyself."}},"definableWords":["one","word","love"],"peopleInVerse":[]},"15":{"text":"But if ye bite and devour one another, take heed that ye be not consumed one of another.","ref":"Galatians 5:15","synthesized":"But if ye bite and devour one another, take heed that ye be not consumed one of another.","sources":{"KJV":{"text":"But if ye bite and devour one another, take heed that ye be not consumed one of another."}},"definableWords":["one"],"peopleInVerse":[]},"16":{"text":"This I say then, Walk in the Spirit, and ye shall not fulfil the lust of the flesh.","ref":"Galatians 5:16","synthesized":"This I say then, Walk in the Spirit, and ye shall not fulfil the lust of the flesh.","sources":{"KJV":{"text":"This I say then, Walk in the Spirit, and ye shall not fulfil the lust of the flesh."}},"definableWords":["walk","Spirit","flesh"],"peopleInVerse":[]},"17":{"text":"For the flesh lusteth against the Spirit, and the Spirit against the flesh: and these are contrary the one to the other: so that ye cannot do the things that ye would.","ref":"Galatians 5:17","synthesized":"For the flesh lusteth against the Spirit, and the Spirit against the flesh: and these are contrary the one to the other: so that ye cannot do the things that ye would.","sources":{"KJV":{"text":"For the flesh lusteth against the Spirit, and the Spirit against the flesh: and these are contrary the one to the other: so that ye cannot do the things that ye would."}},"definableWords":["flesh","Spirit","spirit","one"],"peopleInVerse":[]},"18":{"text":"But if ye be led of the Spirit, ye are not under the law.","ref":"Galatians 5:18","synthesized":"But if ye be led of the Spirit, ye are not under the law.","sources":{"KJV":{"text":"But if ye be led of the Spirit, ye are not under the law."}},"definableWords":["Spirit"],"peopleInVerse":[]},"19":{"text":"Now the works of the flesh are manifest, which are these; Adultery, fornication, uncleanness, lasciviousness,","ref":"Galatians 5:19","synthesized":"Now the works of the flesh are manifest, which are these; Adultery, fornication, uncleanness, lasciviousness,","sources":{"KJV":{"text":"Now the works of the flesh are manifest, which are these; Adultery, fornication, uncleanness, lasciviousness,"}},"definableWords":["works","flesh"],"peopleInVerse":[]},"20":{"text":"Idolatry, witchcraft, hatred, variance, emulations, wrath, strife, seditions, heresies,","ref":"Galatians 5:20","synthesized":"Idolatry, witchcraft, hatred, variance, emulations, wrath, strife, seditions, heresies,","sources":{"KJV":{"text":"Idolatry, witchcraft, hatred, variance, emulations, wrath, strife, seditions, heresies,"}},"definableWords":["wrath"],"peopleInVerse":[]},"21":{"text":"Envyings, murders, drunkenness, revellings, and such like: of the which I tell you before, as I have also told you in time past, that they which do such things shall not inherit the kingdom of God.","ref":"Galatians 5:21","synthesized":"Envyings, murders, drunkenness, revellings, and such like: of the which I tell you before, as I have also told you in time past, that they which do such things shall not inherit the kingdom of God.","sources":{"KJV":{"text":"Envyings, murders, drunkenness, revellings, and such like: of the which I tell you before, as I have also told you in time past, that they which do such things shall not inherit the kingdom of God."}},"definableWords":["kingdom","God"],"peopleInVerse":[]},"22":{"text":"But the fruit of the Spirit is love, joy, peace, longsuffering, gentleness, goodness, faith,","ref":"Galatians 5:22","synthesized":"But the fruit of the Spirit is love, joy, peace, longsuffering, gentleness, goodness, faith,","sources":{"KJV":{"text":"But the fruit of the Spirit is love, joy, peace, longsuffering, gentleness, goodness, faith,"}},"definableWords":["Spirit","love","peace","faith"],"peopleInVerse":[]},"23":{"text":"Meekness, temperance: against such there is no law.","ref":"Galatians 5:23","synthesized":"Meekness, temperance: against such there is no law.","sources":{"KJV":{"text":"Meekness, temperance: against such there is no law."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"And they that are Christ’s have crucified the flesh with the affections and lusts.","ref":"Galatians 5:24","synthesized":"And they that are Christ’s have crucified the flesh with the affections and lusts.","sources":{"KJV":{"text":"And they that are Christ’s have crucified the flesh with the affections and lusts."}},"definableWords":["flesh"],"peopleInVerse":[]},"25":{"text":"If we live in the Spirit, let us also walk in the Spirit.","ref":"Galatians 5:25","synthesized":"If we live in the Spirit, let us also walk in the Spirit.","sources":{"KJV":{"text":"If we live in the Spirit, let us also walk in the Spirit."}},"definableWords":["live","Spirit","walk","spirit"],"peopleInVerse":[]},"26":{"text":"Let us not be desirous of vain glory, provoking one another, envying one another.","ref":"Galatians 5:26","synthesized":"Let us not be desirous of vain glory, provoking one another, envying one another.","sources":{"KJV":{"text":"Let us not be desirous of vain glory, provoking one another, envying one another."}},"definableWords":["one"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"Galatians 6","verses":{"1":{"text":"Brethren, if a man be overtaken in a fault, ye which are spiritual, restore such an one in the spirit of meekness; considering thyself, lest thou also be tempted.","ref":"Galatians 6:1","synthesized":"Brethren, if a man be overtaken in a fault, ye which are spiritual, restore such an one in the spirit of meekness; considering thyself, lest thou also be tempted.","sources":{"KJV":{"text":"Brethren, if a man be overtaken in a fault, ye which are spiritual, restore such an one in the spirit of meekness; considering thyself, lest thou also be tempted."}},"definableWords":["brethren","man","one","spirit"],"peopleInVerse":[]},"2":{"text":"Bear ye one another’s burdens, and so fulfil the law of Christ.","ref":"Galatians 6:2","synthesized":"Bear ye one another’s burdens, and so fulfil the law of Christ.","sources":{"KJV":{"text":"Bear ye one another’s burdens, and so fulfil the law of Christ."}},"definableWords":["one"],"peopleInVerse":[]},"3":{"text":"For if a man think himself to be something, when he is nothing, he deceiveth himself.","ref":"Galatians 6:3","synthesized":"For if a man think himself to be something, when he is nothing, he deceiveth himself.","sources":{"KJV":{"text":"For if a man think himself to be something, when he is nothing, he deceiveth himself."}},"definableWords":["man"],"peopleInVerse":[]},"4":{"text":"But let every man prove his own work, and then shall he have rejoicing in himself alone, and not in another.","ref":"Galatians 6:4","synthesized":"But let every man prove his own work, and then shall he have rejoicing in himself alone, and not in another.","sources":{"KJV":{"text":"But let every man prove his own work, and then shall he have rejoicing in himself alone, and not in another."}},"definableWords":["man","work"],"peopleInVerse":[]},"5":{"text":"For every man shall bear his own burden.","ref":"Galatians 6:5","synthesized":"For every man shall bear his own burden.","sources":{"KJV":{"text":"For every man shall bear his own burden."}},"definableWords":["man"],"peopleInVerse":[]},"6":{"text":"Let him that is taught in the word communicate unto him that teacheth in all good things.","ref":"Galatians 6:6","synthesized":"Let him that is taught in the word communicate unto him that teacheth in all good things.","sources":{"KJV":{"text":"Let him that is taught in the word communicate unto him that teacheth in all good things."}},"definableWords":["word","good"],"peopleInVerse":[]},"7":{"text":"Be not deceived; God is not mocked: for whatsoever a man soweth, that shall he also reap.","ref":"Galatians 6:7","synthesized":"Be not deceived; God is not mocked: for whatsoever a man soweth, that shall he also reap.","sources":{"KJV":{"text":"Be not deceived; God is not mocked: for whatsoever a man soweth, that shall he also reap."}},"definableWords":["God","man"],"peopleInVerse":[]},"8":{"text":"For he that soweth to his flesh shall of the flesh reap corruption; but he that soweth to the Spirit shall of the Spirit reap life everlasting.","ref":"Galatians 6:8","synthesized":"For he that soweth to his flesh shall of the flesh reap corruption; but he that soweth to the Spirit shall of the Spirit reap life everlasting.","sources":{"KJV":{"text":"For he that soweth to his flesh shall of the flesh reap corruption; but he that soweth to the Spirit shall of the Spirit reap life everlasting."}},"definableWords":["flesh","Spirit","spirit","life"],"peopleInVerse":[]},"9":{"text":"And let us not be weary in well doing: for in due season we shall reap, if we faint not.","ref":"Galatians 6:9","synthesized":"And let us not be weary in well doing: for in due season we shall reap, if we faint not.","sources":{"KJV":{"text":"And let us not be weary in well doing: for in due season we shall reap, if we faint not."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"As we have therefore opportunity, let us do good unto all men, especially unto them who are of the household of faith.","ref":"Galatians 6:10","synthesized":"As we have therefore opportunity, let us do good unto all men, especially unto them who are of the household of faith.","sources":{"KJV":{"text":"As we have therefore opportunity, let us do good unto all men, especially unto them who are of the household of faith."}},"definableWords":["good","men","faith"],"peopleInVerse":[]},"11":{"text":"Ye see how large a letter I have written unto you with mine own hand.","ref":"Galatians 6:11","synthesized":"Ye see how large a letter I have written unto you with mine own hand.","sources":{"KJV":{"text":"Ye see how large a letter I have written unto you with mine own hand."}},"definableWords":["see"],"peopleInVerse":[]},"12":{"text":"As many as desire to make a fair shew in the flesh, they constrain you to be circumcised; only lest they should suffer persecution for the cross of Christ.","ref":"Galatians 6:12","synthesized":"As many as desire to make a fair shew in the flesh, they constrain you to be circumcised; only lest they should suffer persecution for the cross of Christ.","sources":{"KJV":{"text":"As many as desire to make a fair shew in the flesh, they constrain you to be circumcised; only lest they should suffer persecution for the cross of Christ."}},"definableWords":["make","flesh","circumcised"],"peopleInVerse":[]},"13":{"text":"For neither they themselves who are circumcised keep the law; but desire to have you circumcised, that they may glory in your flesh.","ref":"Galatians 6:13","synthesized":"For neither they themselves who are circumcised keep the law; but desire to have you circumcised, that they may glory in your flesh.","sources":{"KJV":{"text":"For neither they themselves who are circumcised keep the law; but desire to have you circumcised, that they may glory in your flesh."}},"definableWords":["circumcised","keep","flesh"],"peopleInVerse":[]},"14":{"text":"But God forbid that I should glory, save in the cross of our Lord Jesus Christ, by whom the world is crucified unto me, and I unto the world.","ref":"Galatians 6:14","synthesized":"But God forbid that I should glory, save in the cross of our Lord Jesus Christ, by whom the world is crucified unto me, and I unto the world.","sources":{"KJV":{"text":"But God forbid that I should glory, save in the cross of our Lord Jesus Christ, by whom the world is crucified unto me, and I unto the world."}},"definableWords":["God","Lord"],"peopleInVerse":["Jesus"]},"15":{"text":"For in Christ Jesus neither circumcision availeth any thing, nor uncircumcision, but a new creature.","ref":"Galatians 6:15","synthesized":"For in Christ Jesus neither circumcision availeth any thing, nor uncircumcision, but a new creature.","sources":{"KJV":{"text":"For in Christ Jesus neither circumcision availeth any thing, nor uncircumcision, but a new creature."}},"definableWords":["circumcision"],"peopleInVerse":["Jesus"]},"16":{"text":"And as many as walk according to this rule, peace be on them, and mercy, and upon the Israel of God.","ref":"Galatians 6:16","synthesized":"And as many as walk according to this rule, peace be on them, and mercy, and upon the Israel of God.","sources":{"KJV":{"text":"And as many as walk according to this rule, peace be on them, and mercy, and upon the Israel of God."}},"definableWords":["walk","rule","peace","mercy","Israel","God"],"peopleInVerse":[]},"17":{"text":"From henceforth let no man trouble me: for I bear in my body the marks of the Lord Jesus.","ref":"Galatians 6:17","synthesized":"From henceforth let no man trouble me: for I bear in my body the marks of the Lord Jesus.","sources":{"KJV":{"text":"From henceforth let no man trouble me: for I bear in my body the marks of the Lord Jesus."}},"definableWords":["man","Lord"],"peopleInVerse":["Jesus"]},"18":{"text":"Brethren, the grace of our Lord Jesus Christ be with your spirit. Amen.","ref":"Galatians 6:18","synthesized":"Brethren, the grace of our Lord Jesus Christ be with your spirit. Amen.","sources":{"KJV":{"text":"Brethren, the grace of our Lord Jesus Christ be with your spirit. Amen."}},"definableWords":["brethren","Lord","spirit"],"peopleInVerse":["Jesus"]}}}};